@ARTICLE{10.1186/s40168-026-02343-7,
	author = {Li C(#)(1) and Liu G(#)(1) and Yang Y(1) and Shi Z(1) and Shao Q(1) and Fang Z(1) and Song Y(1) and Gao W(1) and Lei L(1) and Du X(2) and Li X(3).},
	title = {Altered rumen bacterial flora is associated with increased lipogenesis of adipose tissue in obese dairy cows before calving.},
	journal = {Microbiome},
	year = {2026},
	abstract = {BACKGROUND: Prepartum obesity predisposes dairy cows to a higher risk of postpartum metabolic disorder. Volatile fatty acids (VFA) produced through ruminal microbial fermentation of feed substrates serve as a key form of energy for dairy cows. However, the precise mechanisms through which the rumen microbiota promote adipocyte lipid accumulation in obese dairy cows remain to be elucidated. Thus, the aim of this study was to investigate the mechanisms by which rumen microbiota regulates prepartum obesity in dairy cows. RESULTS: Plasma glucose, insulin, triglyceride, and free fatty acids were greater in obese dairy cows. In the adipose tissue, the triglyceride content and expression of genes involved in lipid synthesis were higher in obese dairy cows. In the liver, the expression of genes involved in gluconeogenesis and lipid synthesis was higher in obese dairy cows. The ruminal total VFA, acetate, and propionate were higher in obese dairy cows compared to normal cows. The 16S rRNA gene analysis revealed that rumen bacteria, including Tidjanibacter inops_A, Rikenella massiliensis, Papillibacter cinnamivorans, and Parabacteroides merdae, were enriched in the rumen of obese dairy cows. Enrichment of these bacteria promoted carbohydrate degradation and VFA production. The metabolome analysis showed that obese dairy cows had elevated citric acid level in the rumen, which was positively associated with body condition score, body weight, adipocyte diameter, ruminal VFA concentration, and the abundance of VFA-producing bacteria. CONCLUSIONS: Our results suggest that rumen bacterial flora in prepartum obese dairy cows supply more VFA to the host, which may induce lipid deposition in adipocytes. Video Abstract.},
	doi = {10.1186/s40168-026-02343-7},
	pmid = {41645262 [Indexed for MEDLINE]},
	note = {PMC12895798}
}

@ARTICLE{10.1039/d5fo04520g,
	author = {Ji J(1) and Yu W(2) and Kou X(1) and Chen C(1) and Shao Y(1) and Li J(1) and Lv B(1) and Li J(3) and Xue Z(1).},
	title = {Research advancements on dietary bioactive compounds ameliorating lipid deposition mechanisms via autophagy regulation.},
	journal = {Food Funct},
	year = {2026},
	abstract = {The core pathological basis of obesity and its associated metabolic diseases is excessive lipid deposition. Bioactive compounds from dietary resources, such as polyphenols and flavonoids, can significantly improve lipid homeostatic imbalance by activating autophagy pathways, especially lipophagy. This review gives a systematic analysis of the interaction mechanism between autophagy processes and lipid metabolism, focusing on the elucidation of Rab GTPase-mediated membrane transport, membrane proteins involved in lipid droplet recognition and encapsulation, as well as lipid metabolism enzymes facilitating autophagy-dependent lipid clearance. We further illustrate how dietary bioactive compounds modulate the autophagy network via multiple targets, such as the activation of AMPK or inhibition of mTOR to improve autophagy, the promotion of TFEB nuclear translocation to drive lysosomal production, and the enhancement of SIRT1 to coordinate metabolic stress response. Despite the encouraging lipid-lowering effects of these compounds, there are still challenges related to their pleiotropic targets, discrepancies between in vivo and ex vivo studies, limited bioavailability, and long-term safety. Multidisciplinary approaches should be incorporated into future research to facilitate clinical translation, structure-activity relationship analyses, and evaluations of synergistic effects. This review offers insights for developing autophagy-modulating natural dietary agents as interventions against obesity.},
	doi = {10.1039/d5fo04520g},
	pmid = {41632038 [Indexed for MEDLINE]}
}

